const Database = require('better-sqlite3');
const db = new Database('/workspace/vibers/.nexus/nexus.db');
const patches = [
  ['w-mnt0jin1-960d83b73712', 'completed'],
  ['w-mnswwgah-7dca55bc359e', 'cancelled'],
  ['w-mnszjvrr-87e44398b1e9', 'cancelled'],
  ['w-mnszkcd5-1f3e2acb4f4a', 'cancelled'],
];
const get = db.prepare('SELECT content FROM books_clerk_writs WHERE id = ?');
const set = db.prepare('UPDATE books_clerk_writs SET content = ? WHERE id = ?');
const now = new Date().toISOString();
const tx = db.transaction(() => {
  for (const [id, status] of patches) {
    const row = get.get(id);
    const obj = JSON.parse(row.content);
    obj.status = status;
    obj.updatedAt = now;
    set.run(JSON.stringify(obj), id);
    console.log(id, '->', status);
  }
});
tx();
// verify
for (const [id] of patches) {
  const obj = JSON.parse(get.get(id).content);
  console.log('verify', id, obj.status);
}
" 2>&1

